                for (long long v : graph[u]) {
                    if (comp_id[v] == -1) {
                        comp_id[v] = comp_count;
                        comp_set.insert(v);
                        q.push(v);
                    }
                }
            }
            comp_sets.push_back(comp_set);
            comp_count++;
        }
    }

    vector<long long> ans;
    for (auto& q : queries) {
