#include <vector>
#include <map>
#include <set>
#include <algorithm>
using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<long long> parent(c+1);
    vector<long long> rank(c+1, 0);
    for (long long i = 1; i <= c; i++) {
        parent[i] = i;
    }

    auto find = [&parent](long long x) {
        long long root = x;
        while (root != parent[root]) {
            root = parent[root];
        }
        long long curr = x;
        while (curr != root) {
            long long next = parent[curr];
            parent[curr] = root;
            curr = next;
        }
        return root;
    };

    for (auto& edge : connections) {
        long long u = edge[0];
        long long v = edge[1];
        long long ru = find(u);
        long long rv = find(v);
        if (ru == rv) continue;

        if (rank[ru] < rank[rv]) {
            parent[ru] = rv;
        } else if (rank[ru] > rank[rv]) {
            parent[rv] = ru;
        } else {
            parent[rv] = ru;
            rank[ru]++;
        }
    }

    vector<long long> rootOfNode(c+1);
    for (long long i = 1; i <= c; i++) {
        rootOfNode[i] = find(i);
    }

    map<long long, set<long long>> onlineNodes;
    for (long long i = 1; i <= c; i++) {
        long long r = rootOfNode[i];
        onlineNodes[r].insert(i);
    }

    vector<bool> status(c+1, true);
    vector<long long> ans;

    for (auto& q : queries) {
        long long type = q[0];
        long long x = q[1];
        if (type == 1) {
            if (status[x]) {
                ans.push_back(x);
            } else {
                long long r = rootOfNode[x];
                set<long long>& compSet = onlineNodes[r];
                if (compSet.empty()) {
                    ans.push_back(-1);
                } else {
                    ans.push_back(*(compSet.begin()));
                }
            }
        } else if (type == 2) {
            if (status[x]) {
                status[x] = false;
                long long r = rootOfNode[x];
                onlineNodes[r].erase(x);
            }
        }
    }

    return ans;
}
```

