#include <vector>
#include <queue>
#include <set>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<vector<long long>> adj(c+1);
    for (auto &conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    vector<long long> compRoot(c+1, 0);
    vector<bool> visited(c+1, false);
    vector<set<long long>> comp_set(c+1);

    for (long long i = 1; i <= c; i++) {
        if (!visited[i]) {
            vector<long long> comp_nodes;
            queue<long long> q;
            q.push(i);
            visited[i] = true;
            comp_nodes.push_back(i);
            while (!q.empty()) {
                long long u = q.front();
                q.pop();
                for (long long v : adj[u]) {
                    if (!visited[v]) {
                        visited[v] = true;
                        q.push(v);
                        comp_nodes.push_back(v);
                    }
                }
            }
            long long root = *min_element(comp_nodes.begin(), comp_nodes.end());
            for (long long node : comp_nodes) {
                compRoot[node] = root;
                comp_set[root].insert(node);
            }
        }
    }

    vector<bool> online(c+1, true);
    vector<long long> ans;

    for (auto &qry : queries) {
        long long type = qry[0];
        long long x = qry[1];
        if (type == 1) {
            if (online[x]) {
                ans.push_back(x);
